mapper.select:
SELECT WLF_UNIQ_NO, WLF_FLNM_CNTT, WLF_FIRST_NAME_CNTT, WLF_MIDDLE_NAME_CNTT,
       WLF_LAST_NAME_CNTT, WLF_NTNT_CNTT, SPLM_DATE, SANCTION_TP, LIST_DT,
       USE_CCD, REG_DT
FROM NIC19B_FACTIVA_UA
WHERE 1=1

    AND (UPPER(WLF_FLNM_CNTT) LIKE '%' || UPPER(#{wlNm}) || '%'
      OR UPPER(WLF_FIRST_NAME_CNTT) LIKE '%' || UPPER(#{wlNm}) || '%'
      OR UPPER(WLF_LAST_NAME_CNTT) LIKE '%' || UPPER(#{wlNm}) || '%')


    AND WLF_NTNT_CNTT = #{wlSrcCd}


    AND SANCTION_TP = #{wlTpCd}


    AND USE_CCD = #{useYn}

ORDER BY REG_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC19B_FACTIVA_UA
WHERE 1=1

    AND (UPPER(WLF_FLNM_CNTT) LIKE '%' || UPPER(#{wlNm}) || '%'
      OR UPPER(WLF_FIRST_NAME_CNTT) LIKE '%' || UPPER(#{wlNm}) || '%'
      OR UPPER(WLF_LAST_NAME_CNTT) LIKE '%' || UPPER(#{wlNm}) || '%')


    AND WLF_NTNT_CNTT = #{wlSrcCd}


    AND SANCTION_TP = #{wlTpCd}


    AND USE_CCD = #{useYn}

mapper.insert:
