) VALUES (
    #{wlNm}, #{wlSrcCd}, #{sanctionTp}, #{listDt}, #{birthDt}, #{useYn}, CURRENT_TIMESTAMP
)

mapper.select:
SELECT SCREEN_ID, RNMCNO, WLF_UNIQ_NO, MATCH_SCR, MATCH_ST_CCD, SCREEN_DT,
       REVIEW_ID, REVIEW_DT, REMARK, REG_ID, REG_DT, UPD_ID, UPD_DT
FROM WL_SCREEN_RSLT
WHERE 1=1

    AND RNMCNO = #{custNo}


    AND MATCH_ST_CCD = #{matchStCd}

ORDER BY SCREEN_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM WL_SCREEN_RSLT
WHERE 1=1

    AND RNMCNO = #{custNo}


    AND MATCH_ST_CCD = #{matchStCd}
